class Solution:
    def minimumCost(self, s: str) -> int:
        n = len(s)
        cost = 0
        ones = 0
        for i in range(n):
            if s[i] == '1':
                ones += 1
            if i == n - 1 or s[i + 1] != s[i]:
                cost += min(i + 1 + ones, n - i)
                ones = 0
        return cost

